var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"……그래서, 백작가문에 데릴사위로 들어가기로 했다?","JPN":"……それで、伯爵家の入り婿になったと？","ENG":"...So you're saying you're marrying into the Birmingham family?","TWN":"……所以，你決定入贅伯爵家了？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"예. 어쩌다 보니 그렇게 됐군요.","JPN":"はい。成り行きでそうなりました。","ENG":"Yes. It just sort of happened that way.","TWN":"是的，事情就變成這樣了。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"어쩌다는 무슨. 대체 무슨 짓을 하면 양이나 치던 놈이 백작가의 후계자를 꼬셔?","JPN":"成り行きなわけないだろう。いったいどうやって羊飼いが伯爵家の後継者を口説いたんだ？","ENG":"Just happened? What on earth did you pull to make the Count's heir fall for a shepherd?","TWN":"你少來。到底要做什麼才能讓一個放羊的傢伙勾引到伯爵家的繼承人？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"거기에, 뭐? 구원기사단의 단장이 됐다고? 지금 나보고 그 말을 믿으라는 거냐?","JPN":"それに、何だ？　救世騎士団の団長になった？　それを信じろというのか？","ENG":"And what's this about becoming the captain of the Knights of Redemption? You expect me to believe that?","TWN":"你說什麼？你說你現在是救贖騎士團的團長？鬼才相信。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"제국의 황태자 전하께서는 능력 위주로 사람을 인선하십니다.","JPN":"帝国の皇太子殿下は能力で人をお選びになります。","ENG":"His Highness, the Crown Prince, selects people based on ability.","TWN":"帝國的皇太子殿下是以能力為主來選拔人才的。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"평민 출신의 기사도 여럿 있으니, 양치기 출신이 기사단의 단장이어도 이상함은 없죠.","JPN":"平民出身の騎士も数人いますので、羊飼い出身が騎士団の団長だとしてもおかしくはないんです。","ENG":"There are several knights of common birth, so it's not strange for a former shepherd to become a captain.","TWN":"既然有不少平民出身的騎士，那麼牧羊人出身的騎士團團長也沒有什麼奇怪的。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"……허어, 어렸을 때부터 크게 될 놈이라고는 생각했지만 설마 이정도로 출세할 줄이야.","JPN":"ほう、小さい頃から大物になるとは思っていたんだが、ここまで出世するとはな。","ENG":"Huh. I always knew you'd do well, but I didn't think you'd go this far.","TWN":"……哈，我從小就覺得你這傢伙會有出息，但沒想到會出人頭地到這種程度。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"그럼 결혼식은 언제 올릴 생각이냐?","JPN":"じゃあ、結婚式はいつ挙げるんだ？","ENG":"So, when's the wedding?","TWN":"那麼你打算什麼時候舉行婚禮呢？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"전시 상황인 만큼 둘이서 간단하게 식을 치르기로 했습니다.","JPN":"戦時なので、2人だけで簡単に挙げることにしました。","ENG":"Given the wartime situation, we've decided to hold a small private ceremony.","TWN":"由於是戰爭期間，我們決定簡單地舉行儀式。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"제 출신이 출신인 만큼, 아내가 배려해 준 것이겠죠.","JPN":"私の出身もありますので、妻が配慮してくれたのでしょう。","ENG":"It's probably her way of being considerate, knowing my background.","TWN":"因為我的出身，妻子才會如此體貼吧。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"……넌 진짜 아내한테 잘해라.","JPN":"……奥さんによくしてやれよ。","ENG":"...You'd better treat her well.","TWN":"……你可要對你妻子好一點。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"말씀처럼 그럴 생각입니다.","JPN":"はい、そのつもりです。","ENG":"I intend to. Just as you said.","TWN":"我也是這麼想的。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"그런데 청첩장 돌리러 온 것도 아니면 마을에는 왜 돌아온 게냐?","JPN":"で、招待状を配るわけでもないのに、村にはどうして帰ってきたんだ？","ENG":"So if you're not here to hand out wedding invitations, why'd you come back to the village?","TWN":"那麼，如果不是來發請帖的話，為什麼要回到村子裡呢？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"소식을 전하기 위함도 있지만, 다른 용건들도 있습니다.","JPN":"近況を知らせるためでもありますが、他に用事がありまして。","ENG":"Partly to share the news, but I had other reasons, too.","TWN":"雖然是為了傳達消息，但也有其他事情。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"아내가 마을에 오기를 원했기도 하고…….","JPN":"妻が村に来たいと言っていたのもありますし……","ENG":"My wife wanted to visit the village, and...","TWN":"妻子也希望能來村子……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"만나야 할 사람이 한 명 더 있으니까요.","JPN":"会うべき人がもう一人いますから。","ENG":"There's one more person I need to see.","TWN":"因為還有一個人我們必須見。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"그래. 그랬었지, 참.","JPN":"ああ。そうだったな、そういえば。","ENG":"Right, I almost forgot.","TWN":"對，沒錯。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"UNCLE_NPC_NULL_NULL","text":{"KOREA":"그녀석이라면 평소처럼 말을 돌보고 있을 테니, 그리로 가보거라.","JPN":"あいつならいつもどおり馬の世話をしているはずだ。そこに行ってみろ。","ENG":"If it's him, he's probably tending the horses as usual. You should head that way.","TWN":"如果是那傢伙的話，應該像平時一樣在照看馬匹，去那裡看看吧。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"예. 감사합니다, 숙부님.","JPN":"はい。ありがとうございます、叔父さん。","ENG":"Thank you, Uncle.","TWN":"好的，謝謝你，叔叔。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"영주님네 마구간에서 조금 걸으면, 어릴 적 울타리를 넘은 말이 남긴 말발굽 자국이 있지.","JPN":"領主の馬小屋からもう少し歩くと、幼い頃柵を越えた馬が残したひづめの跡がある。","ENG":"Just past the stables, there's a spot where a horse once jumped the fence and left hoofprints.","TWN":"在領主家的馬廄走一會兒，就能看到小時候越過圍欄的馬留下的馬蹄印。"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그 길을 따라 쭉 걷다 보면, 마을 중심에 있는 나무 앞에 도착하고.","JPN":"その道に沿って歩いていくと、村の中心にある木の前にたどり着いて。","ENG":"If you follow that trail, it leads to the big tree at the village center.","TWN":"沿著那條路一直走，就會到達村莊中心的那棵樹前。"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고 거기가 늘 알렌과의 대련 장소였지.","JPN":"そして、そこがいつもアレンと立ち合い稽古してたところだったよね。","ENG":"That was always the spot where Allen and I used to spar.","TWN":"而且那裡一直是和艾倫對練的地方。"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"그립네. 어렸을 적에는 늘 그러고 놀았는데.","JPN":"懐かしいな。小さい時はいつもそうやって遊んでたのに。","ENG":"I miss those days. We used to play like that all the time.","TWN":"懷念啊。小時候總是這樣玩。"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"여전하군.","JPN":"相変わらずだな。","ENG":"Still the same, I see.","TWN":"依舊如故。"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"약속하지도 않았는데 이리 만난 걸 보면, 너랑은 인연이 있는 걸지도 모르겠어.","JPN":"約束もしていないのにこうやって出会うのは、君とは絆があるのかもしれない。","ENG":"Funny how we keep running into each other without even making plans. Maybe it's fate.","TWN":"雖然沒有約定，但能在這裡遇見你，或許我們之間有緣分吧。"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"그러게. 나도 어쩐지 그런 기분이 들었어.","JPN":"そうだね。僕もなんとなくそんな気がしてたよ。","ENG":"Yeah. I was just thinking the same thing.","TWN":"是啊，我也莫名有這種感覺。"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_NULL","text":{"KOREA":"오랜만이야, 알렌. 센트럴 팰리스에서의 생활은 어때?","JPN":"久しぶり、アレン。セントラルパレスでの生活はどう？","ENG":"It's been a while, Allen. How's life at Central Palace?","TWN":"好久不見，艾倫。在聖特羅貝里斯的生活怎麼樣？"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};